// Helper to match ingredient strings to pantry
function matchIngredient(ingredientStr, pantryIds, library) {
  const str = ingredientStr.toLowerCase();
  for (const id of pantryIds) {
    const libItem = library.ingredients?.find(i => i.id === id);
    if (!libItem) continue;
    for (const term of libItem.searchTerms || []) {
      if (str.includes(term.toLowerCase())) {
        return { matched: true, pantryItem: libItem };
      }
    }
  }
  // Try matching against spirit guide
  for (const spirit of library.spiritGuide || []) {
    for (const term of spirit.searchTerms || []) {
      if (str.includes(term.toLowerCase())) {
        return { matched: true, pantryItem: spirit };
      }
    }
  }
  return { matched: false };
}

// Calculate recipe match score
function calculateMatchScore(recipeIngredients, pantryIds, library) {
  if (!recipeIngredients || recipeIngredients.length === 0) return 0;
  let matched = 0;
  for (const ingredient of recipeIngredients) {
    const result = matchIngredient(ingredient, pantryIds, library);
    if (result.matched) matched++;
  }
  return Math.round((matched / recipeIngredients.length) * 100);
}

// Get missing ingredients
function getMissingIngredients(recipeIngredients, pantryIds, library) {
  const missing = [];
  if (!recipeIngredients) return missing;
  for (const ingredient of recipeIngredients) {
    const result = matchIngredient(ingredient, pantryIds, library);
    if (!result.matched) {
      missing.push(ingredient);
    }
  }
  return missing;
}

