function matchIngredient(str, pantryIds) {
  const s = str.toLowerCase();
  for (const id of pantryIds) {
    const item = LIBRARY.ingredients.find(i => i.id === id);
    if (!item) continue;
    for (const term of (item.searchTerms || [])) {
      if (s.includes(term.toLowerCase())) return { matched: true, item };
    }
  }
  // Also check spirits
  for (const sp of (LIBRARY.spiritGuide || [])) {
    if (pantryIds.includes(sp.id)) {
      for (const term of (sp.searchTerms || [])) {
        if (s.includes(term.toLowerCase())) return { matched: true, item: sp };
      }
    }
  }
  return { matched: false };
}

function calcScore(ingredients, pantryIds) {
  if (!ingredients || ingredients.length === 0) return 0;
  let matched = 0;
  for (const ing of ingredients) {
    const ingStr = typeof ing === 'string' ? ing : (ing.name || '');
    if (!ingStr) continue;
    // Skip pure garnish/ice
    const lower = ingStr.toLowerCase();
    if (lower === 'ice' || lower === 'crushed ice' || lower === 'large ice cubes' || lower === 'ice cubes') { matched++; continue; }
    if (matchIngredient(ingStr, pantryIds).matched) matched++;
  }
  return Math.round((matched / ingredients.length) * 100);
}

function getMissing(ingredients, pantryIds) {
  if (!ingredients) return [];
  return ingredients.filter(ing => {
    const s = typeof ing === 'string' ? ing : (ing.name || '');
    if (!s) return false;
    const lower = s.toLowerCase();
    if (lower === 'ice' || lower === 'crushed ice' || lower === 'large ice cubes' || lower === 'ice cubes') return false;
    return !matchIngredient(s, pantryIds).matched;
  }).map(ing => typeof ing === 'string' ? ing : (ing.name || ''));
}

